checker_dsl:
EXISTS (`DataFlow::Node sinkNode`) {
  EXISTS (`DataFlow::Node sourceNode`) {
    AND {
      (`sourceNode is an instance of ActiveThreatModelSource`),
      (`sinkNode is an instance of TaintedPathSink`),
      EXISTS (`TaintTracking::PathNode sourcePathNode`, `TaintTracking::PathNode sinkPathNode`) {
        AND {
          (`sourcePathNode corresponds to sourceNode`),
          (`sinkPathNode corresponds to sinkNode`),
          (`there exists a taint flow path from sourcePathNode to sinkPathNode`)
        }
      },
      NOT {
        EXISTS (`DataFlow::Node barrierNode`) {
          OR {
            (`barrierNode is an instance of SimpleTypeSanitizer`),
            (`barrierNode is an instance of PathInjectionSanitizer`)
          }
        }
      },
      FORALL (`DataFlow::Node n1`, `DataFlow::Node n2`) {
        (`if n1 is tainted and there is a direct dataflow step from n1 to n2 that is not a standard taint step, then n2 becomes tainted`)
      }
    }
  }
}
